import { workflow, trigger, node, expr } from '@n8n/workflow-sdk';

const manualTrigger = trigger({
  type: 'n8n-nodes-base.manualTrigger',
  version: 1,
  config: { name: 'Manual Trigger' }
});

const setFields = node({
  type: 'n8n-nodes-base.set',
  version: 3.4,
  config: {
    name: 'Set Fields',
    parameters: {
      mode: 'manual',
      includeOtherFields: false,
      assignments: {
        assignments: [
          {
            id: 'field-1',
            name: 'exampleField',
            value: 'exampleValue',
            type: 'string'
          },
          {
            id: 'field-2',
            name: 'timestamp',
            value: expr('{{ $now.toISO() }}'),
            type: 'string'
          }
        ]
      }
    }
  }
});

export default workflow('close-preview-test', 'close preview test')
  .add(manualTrigger)
  .to(setFields);
